w", "companyName": "Gaa Bangkok", "connections": "2446", "currentJobDuration": "2 yrs 3 mos", "currentJobDurationInYrs": "2.25", "educations/0/companyId": "13596", "educations/0/companyLink1": "https://www.linkedin.com/school/punjab-technical-university/", "educations/0/companyUrn": "urn:li:fsd_company:13596", "educations/0/grade": "1st Div", "educations/0/logo": "https://media.licdn.com/dms/image/v2/C4D0BAQGQnCyBiC1ZJw/company-logo_200_200/company-logo_200_200/0/1631310643756?e=1778112000&v=beta&t=gwPX-iDK6xyTOgGtwYB_LCmwDfFCrwDo_rWikE1lfV8", "educations/0/period/endedOn/month": "10", "educations/0/period/endedOn/year": "2011", "educations/0/period/startedOn/month": "3", "educations/0/period/startedOn/year": "2008", "educations/0/subtitle": "Hotel Management Bachelor Degree, Hotel, Motel, and Restaurant Management", "educations/0/title": "Punjab Technical University", "educations/1/companyId": "13596", "educations/1/companyLink1": "https://www.linkedin.com/school/punjab-technical-university/", "educations/1/companyUrn": "urn:li:fsd_company:13596", "educations/1/grade": "A", "educations/1/logo": "https://media.licdn.com/dms/image/v2/C4D0BAQGQnCyBiC1ZJw/company-logo_200_200/company-logo_200_200/0/1631310643756?e=1778112000&v=beta&t=gwPX-iDK6xyTOgGtwYB_LCmwDfFCrwDo_rWikE1lfV8", "educations/1/period/endedOn/month": "5", "educations/1/period/endedOn/year": "2011", "educations/1/period/startedOn/month": "5", "educations/1/period/startedOn/year": "2008", "educations/1/subtitle": "Bachelor's degree, Hotel, Motel, and Restaurant Management", "educations/1/title": "Punjab Technical University", "educations/2/period/endedOn/month": "0", "educations/2/period/endedOn/year": "0", "educations/2/period/startedOn/month": "0", "educations/2/period/startedOn/year": "0", "educations/2/subtitle": "Introductory Sommelier , Wine Steward/Sommelier", "educations/2/title": "Court of Master Sommelier", "educations/3/period/endedOn/month": "0", "educations/3/period/endedOn/year": "0", "educat